        async def _stop_utbreak_trading():
            await _ensure_signal_engine_active()
            self.is_paused = True
            await self.cfg.update_value(['signal_engine', 'strategy_params', 'active_strategy'], UTBOT_FILTERED_BREAKOUT_STRATEGY)
